import pandas as pd
users = pd.DataFrame({
    'user_id': [101, 102, 103],
    'username': ['userA', 'userB', 'userC']
})
purchases = pd.DataFrame({
    'purchase_id': [1, 2, 3, 4],
    'user_id': [101, 102, 101, 104],
    'amount': [25.0, 50.0, 15.0, 100.0]
})
result = pd.merge(users, purchases, on='user_id')

